import Button from 'app/components/sharedV2/Button';
import TextField from 'app/components/sharedV2/TextField';
import manualSensorDataStore from 'app/stores/sensors/manualSensorDataStore';
import dayjs from 'dayjs';
import {useCallback, useEffect, useState} from 'react';
import {FormProvider, useForm} from 'react-hook-form';

const {i18n} = __;
const {dateUiFormat, dateApiFormat} = __.app;

const SensorForm = ({sensor, updateSensorData}) => {
  const methods = useForm({
    defaultValues: {
      date: dayjs().format(dateUiFormat),
      time: dayjs().format('HH:mm'),
      index: 0,
      sensorCode: sensor.code,
    },
  });

  const {handleSubmit, errors} = methods;

  const onSubmit = async (data) => {
    const formattedData = [
      {
        sensorCode: data.sensorCode,
        recDate: dayjs(data.date, dateUiFormat).format(dateApiFormat),
        recTime: data.time,
        index: data.index.toString(),
      },
    ];

    try {
      await manualSensorDataStore.create(formattedData, {}, {shouldThrow: true}).then(() => {
        __.ui.notifySuccess(
          i18n.t('ManualDataImport.dataImportSuccess') + ' ' + sensor.name + ' \nIndex : ' + formattedData[0].index,
        );
      });
      methods.reset({
        date: dayjs().format(dateUiFormat),
        time: dayjs().format('HH:mm'),
        index: 0,
        sensorCode: sensor.code,
      });

      const res = await manualSensorDataStore.fetchAll(sensor.id, dayjs().year(), 1, 'desc');
      updateSensorData(sensor.id, res.data);
    } catch (error) {
      console.error('Error submitting sensor data:', error);
    }
  };

  return (
    <FormProvider {...methods}>
      <form
        onSubmit={handleSubmit(onSubmit)}
        className='tw-my-2'
      >
        <h2 className='tw-font-semibold tw-mb-2'>{sensor.name}</h2>
        <div className='md:tw-flex-row tw-flex-col tw-flex tw-gap-2'>
          <TextField
            label={i18n.t('ManualDataImport.date')}
            name='date'
            errors={errors?.date?.message}
          />
          <TextField
            label={i18n.t('ManualDataImport.time')}
            name='time'
            errors={errors?.time?.message}
          />
          <TextField
            label={i18n.t('ManualDataImport.index')}
            name='index'
            type={'number'}
            step={0.1}
            errors={errors?.index?.message}
          />
        </div>
        <div className='tw-flex tw-flex-row tw-gap-2 tw-justify-center'>
          <Button type='submit'>{i18n.t('BaseForm.validate')}</Button>
        </div>
      </form>
    </FormProvider>
  );
};

const DisplaySensorsData = ({manualSensors}) => {
  const [manualSensorData, setManualSensorData] = useState({});

  const updateSensorData = useCallback((sensorId, newData) => {
    setManualSensorData((prev) => ({
      ...prev,
      [sensorId]: newData,
    }));
  }, []);

  useEffect(() => {
    if (!manualSensors || manualSensors.length === 0) return;

    manualSensors.forEach((sensor) => {
      manualSensorDataStore.fetchAll(sensor.id, dayjs().year(), 1, 'desc').then((res) => {
        setManualSensorData((prev) => ({
          ...prev,
          [sensor.id]: res.data,
        }));
      });
    });
  }, [manualSensors]);

  return (
    <div className='tw-mt-4'>
      <h1 className='tw-text-lg tw-font-bold tw-mb-4'>{i18n.t('ManualDataImport.sensorsData')}</h1>
      <div className='tw-overflow-x-auto'>
        {manualSensors.map((sensor) => (
          <SensorForm
            key={sensor.id}
            sensor={sensor}
            updateSensorData={updateSensorData}
          />
        ))}
        {manualSensors.length === 1 && (
          <table className='tw-min-w-full tw-bg-white tw-border tw-border-gray-300 tw-text-sm sm:tw-text-base tw-mb-4'>
            <thead>
              <tr className='tw-bg-gray-200'>
                <th className='tw-py-4 tw-border tw-text-center'>{i18n.t('ManualDataImport.date')}</th>
                <th className='tw-py-4 tw-border tw-text-center'>{i18n.t('ManualDataImport.time')}</th>
                <th className='tw-py-4 tw-border tw-text-center'>{i18n.t('ManualDataImport.index')}</th>
                <th className='tw-py-4 tw-border tw-text-center'>{i18n.t('ManualDataImport.value')}</th>
                <th />
              </tr>
            </thead>
            <tbody>
              {manualSensors.map((sensor) =>
                (manualSensorData[sensor.id] || []).map((data, index) => (
                  <tr
                    key={`${sensor.id}-${index}`}
                    className='tw-border'
                  >
                    <td className='tw-py-4 tw-border tw-text-center'>
                      {dayjs(data.recDate, 'YYYY-MM-DD').format('DD/MM/YYYY')}
                    </td>
                    <td className=' tw-py-4 tw-border tw-text-center'>
                      {dayjs(data.recTime, 'HH:mm:ss').format('HH:mm')}
                    </td>
                    <td className='tw-py-4 tw-border tw-text-center'>{Number(data.index).toFixed(1)}</td>
                    <td className='tw-py-4 tw-border tw-text-center'>{Number(data.value).toFixed(1)}</td>
                    <td className='tw-py-4 tw-border tw-text-center'>
                      <i
                        className='fa fa-trash modal-icon'
                        onClick={() => null}
                      />
                    </td>
                  </tr>
                )),
              )}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default DisplaySensorsData;
