/* eslint-disable max-statements */
import Dropdown from 'app/components/shared/Dropdown';
import manualSensorDataStore from 'app/stores/sensors/manualSensorDataStore';
import {useEffect, useState} from 'react';
import Title from 'app/components/shared/Title';
import Loader from 'app/components/shared/Loader';
import {useStore} from 'app/hooks/store';
import {useCallback} from 'react';
import {FormProvider, useForm} from 'react-hook-form';
import Table from 'app/components/shared/Table';
import sensorStore from 'app/stores/sensors/sensorStore';
import reactHookFormValidations from 'app/utils/reactHookFormValidations';
import EditSensorDataBody from './EditSensorDataBody';
import dayjs from 'dayjs';
import Button from 'app/components/sharedV2/Button';
import Modal from 'app/components/sharedV2/Modal';

const {i18n, acl} = __;

function EditManualSensorData({sensorId, lastIndex, onYearChange, year}) {
  const [isLoading, setIsLoading] = useState(false);
  const store = manualSensorDataStore;
  const today = new Date();
  const toMonth = new Date(today.getFullYear() - 10, 0, 1);
  const [rowToDelete, setRowToDelete] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [sensorData, setSensorData] = useState([]);
  const [isDataFetched, setIsDataFetched] = useState(false);

  const methods = useForm();

  const years = [];
  for (let i = today.getFullYear(); i >= toMonth.getFullYear(); i--) {
    let year = {
      label: i.toString(),
    };
    years.push(year);
  }

  useStore(store, () => {
    setIsLoading(store.getState().isLoading);
  });

  const updateStoreCb = useCallback(() => {
    const allData = [...store.getState().manualSensorDatas];
    allData.sort((a, b) => {
      return dayjs(b.recDate + ' ' + b.recTime).unix() - dayjs(a.recDate + ' ' + a.recTime).unix();
    });
    setSensorData(allData);
    methods.reset();
  }, [store, setSensorData]);

  useStore(store, updateStoreCb);

  const validateData = (datas, length) => {
    const validations = reactHookFormValidations();
    for (let index = 0; index < length; index++) {
      if (!validations.validateIndex(datas['index_' + index])) {
        return false;
      }
      if (
        !validations.validateDate(dayjs(datas['recDate_' + index], __.app.dateUiFormat).format(__.app.dateApiFormat))
      ) {
        return false;
      }
      if (!validations.validateTime(datas['recTime_' + index])) {
        return false;
      }
    }
    return true;
  };

  const handleManualDataDeletion = (sensorId, recDate, recTime) => {
    const sensorList = sensorData;
    sensorList.splice(rowToDelete, 1);
    setSensorData(sensorList);

    for (let i = 0; i < sensorList.length; i++) {
      let obj = sensorList[i];
      obj['rec_time'] = dayjs(`0000-01-01 ${obj['recTime']}`).format('HH:mm');
      obj['rec_date'] = obj['recDate'];
      delete obj.value;
      sensorList[i] = obj;
    }
    const sensorInfos = {
      sensor_id: sensorId,
      date_begin: dayjs(`${year}-01-01`).format('YYYY-MM-DD'),
      date_end: dayjs(`${year}-12-31`).format('YYYY-MM-DD'),
      datas: sensorList,
    };
    store.update(sensorInfos, {}, {shouldThrow: true}).then(() => {
      store.fetchAll(sensorId, year, 1);
    });
  };

  useEffect(() => {
    if (!isDataFetched) {
      store.fetchAll(sensorId, year, 1).then((res) => {
        setIsDataFetched(true);
      });
    }
  }, [isDataFetched, sensorId]);

  useEffect(() => {
    setIsDataFetched(false);
  }, [sensorId]);

  const handleRowDeletion = (value, data) => {
    if (value === false) {
      setShowModal(false);
      return;
    }
    handleManualDataDeletion(data.sensorId, data.recDate, data.recTime);
    setShowModal(false);
  };

  const handleOnClick = (id) => {
    setRowToDelete(id);
    setShowModal(true);
  };

  const groupDataByNumber = (data) => {
    const groupedData = [];

    for (const key in data) {
      const match = key.match(/(\w+)_(\d+)/);
      if (match) {
        const [, prefix, number] = match;
        if (!groupedData[number]) {
          groupedData[number] = {};
        }
        groupedData[number][prefix] = data[key];
      }
    }
    return groupedData;
  };

  const submit = (data) => {
    let formattedData = [];
    const groupedData = groupDataByNumber(data);

    if (!validateData(data, groupedData.length)) {
      __.ui.notify('error', i18n.t('ManualSensorDataForm.invalidData'));
      return;
    }
    groupedData.map((data, index) => {
      formattedData.push({
        rec_date: moment(groupedData[index].recDate, __.app.dateUiFormat).format(__.app.dateApiFormat),
        rec_time: moment(groupedData[index].recTime, 'HH:mm').format('HH:mm'),
        sensor_code: sensorStore.getState().sensor.code,
        index: methods.getValues('index_' + index),
      });
    });

    const addSensorInfo = {
      sensor_id: sensorId,
      date_begin: dayjs(`${year}-01-01`).format('YYYY-MM-DD'),
      date_end: dayjs(`${year}-12-31`).format('YYYY-MM-DD'),
      datas: formattedData,
    };
    store.update(addSensorInfo, {}, {shouldThrow: true}).then(() => {
      store.fetchAll(sensorId, year, 1);
    });
  };

  const onSubmit = (data) => submit(data);

  return (
    <>
      <Title
        title={i18n.t('ManualSensorDataForm.editionTitle')}
        level={1}
      />
      <div className='f f-between stick-update'>
        <Dropdown
          btnId='years-dropdown'
          className='dropdown-reset dropdown-btn'
          items={years}
          label={year}
          onSelect={(e, item) => {
            onYearChange(item.label);
          }}
        />
        {sensorData.length ? (
          <Button
            type='submit'
            onClick={methods.handleSubmit(onSubmit)}
          >
            {i18n.t('BaseForm.validate')}
          </Button>
        ) : null}
      </div>
      {!isLoading ? (
        <FormProvider {...methods}>
          <form>
            <div className='table-container'>
              <Table>
                <tbody>
                  {sensorData.map((data, id) => (
                    <tr key={`${data.recDate}${data.recTime}${data.index}`}>
                      <td>
                        <div className='table-data-container'>
                          <EditSensorDataBody
                            id={id}
                            data={data}
                            key={`${data.recDate}${data.recTime}${data.index}`}
                          />
                          <i
                            className='fa fa-trash modal-icon'
                            onClick={() => handleOnClick(id)}
                          />
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </Table>
              {sensorData.length ? null : (
                <div className='f-center f-align-center f-column'>
                  <div
                    className='empty-logo'
                    alt={i18n.t('Graph.noData')}
                    style={{
                      opacity: '0.5',
                      maxHeight: '260px',
                    }}
                  />
                  <p>{i18n.t('Graph.noDataPeriod')}</p>
                </div>
              )}
            </div>
          </form>
          <Modal
            alertType='warning'
            type={'confirm'}
            title={i18n.t('GenericModal.title.confirmRequired')}
            content={i18n.t('ManualSensorDataForm.form.actions.deleteIndexConfirmation')}
            onChange={(value) => {
              handleRowDeletion(value, sensorData[rowToDelete]);
            }}
            modal={showModal}
            onFocusOff={() => setShowModal(false)}
            cross
          />
        </FormProvider>
      ) : (
        <Loader />
      )}
    </>
  );
}

export default EditManualSensorData;
